import{_ as e,o as s,c as i,a0 as l}from"./chunks/framework.M0_h-cZU.js";const t="/vitepress-study/assets/nuxt3_26_01.B5oPyRE0.png",b=JSON.parse('{"title":"Nuxt3 學習筆記 - Ryan","description":"","frontmatter":{"title":"Nuxt3 學習筆記 - Ryan"},"headers":[],"relativePath":"pages/f2e/docVue/nuxt/nuxt3/nuxt3-26.md","filePath":"pages/f2e/docVue/nuxt/nuxt3/nuxt3-26.md"}'),c={name:"pages/f2e/docVue/nuxt/nuxt3/nuxt3-26.md"};function n(o,a,d,h,r,p){return s(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="_26-public-與-assets-資源目錄" tabindex="-1">26. Public 與 Assets 資源目錄 <a class="header-anchor" href="#_26-public-與-assets-資源目錄" aria-label="Permalink to &quot;26. Public 與 Assets 資源目錄&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><ul><li><p>在使用 <code>create-vue</code> 建立的 <code>Vue</code> 專案中，通常包含 <code>public</code> 與 src 內的 <code>assets</code> 目錄，兩者皆可用於存放不常變動的靜態資源。</p></li><li><p>然而，這兩個目錄因其特性不同，建議放置的檔案類型與使用目的也有所區別。</p></li></ul><h2 id="nuxt-3-的靜態資源" tabindex="-1">Nuxt 3 的靜態資源 <a class="header-anchor" href="#nuxt-3-的靜態資源" aria-label="Permalink to &quot;Nuxt 3 的靜態資源&quot;">​</a></h2><p><code>Nuxt 3</code> 使用專案下的兩個主要目錄來處理<code>圖片</code>、<code>樣式（CSS/SCSS）</code>或<code>字體</code>等資源，分別是 <code>public</code> 與 <code>assets</code>。</p><ul><li><h3 id="public-目錄" tabindex="-1">public 目錄 <a class="header-anchor" href="#public-目錄" aria-label="Permalink to &quot;public 目錄&quot;">​</a></h3><ul><li><h4 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h4><p>等同於 <code>Vue</code> 中的 <code>public</code> 目錄或 Nuxt 2 中的 <code>static</code> 目錄。</p></li><li><h4 id="路徑映射" tabindex="-1">路徑映射 <a class="header-anchor" href="#路徑映射" aria-label="Permalink to &quot;路徑映射&quot;">​</a></h4><p>此目錄下的檔案將會由 <code>Nuxt</code> 直接映射並對應到網站的根路徑（<code>/</code>）提供存取。</p></li><li><h4 id="範例" tabindex="-1">範例 <a class="header-anchor" href="#範例" aria-label="Permalink to &quot;範例&quot;">​</a></h4><p>若將一張圖片放在 <code>./public/bg.png</code>，在網頁模板中直接使用 <code>&lt;img src=&quot;/bg.png&quot; /&gt;</code> 即可成功讀取與顯示。</p></li></ul></li><li><h3 id="assets-目錄" tabindex="-1">assets 目錄 <a class="header-anchor" href="#assets-目錄" aria-label="Permalink to &quot;assets 目錄&quot;">​</a></h3><ul><li><h3 id="特性-1" tabindex="-1">特性 <a class="header-anchor" href="#特性-1" aria-label="Permalink to &quot;特性&quot;">​</a></h3><p>此目錄適合放置需要經過編譯工具（如 <code>Vite</code> 或 <code>Webpack</code>）進行轉換、壓縮、加工或處理的資源（例如包含 Scss/Less 的樣式表、需要優化的圖片）。</p></li><li><h3 id="使用別名" tabindex="-1">使用別名 <a class="header-anchor" href="#使用別名" aria-label="Permalink to &quot;使用別名&quot;">​</a></h3><p>在程式碼中引用 <code>assets</code> 目錄時，可使用 <code>~/assets</code> 或 <code>@/assets</code> 作為路徑別名（Alias）來代表相對路徑。</p></li><li><h3 id="範例-1" tabindex="-1">範例 <a class="header-anchor" href="#範例-1" aria-label="Permalink to &quot;範例&quot;">​</a></h3><p>若將圖片放置於 <code>./assets/bg.png</code>，則可在網頁中寫作：</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">template</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~/assets/bg.png&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">template</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>在開發環境下，該路徑會被轉換為 <code>/_nuxt/assets/bg.png</code> 並可直接訪問。</li></ul></li></ul></li></ul><h2 id="public-與-assets-的打包差異" tabindex="-1">public 與 assets 的打包差異 <a class="header-anchor" href="#public-與-assets-的打包差異" aria-label="Permalink to &quot;public 與 assets 的打包差異&quot;">​</a></h2><ul><li><h3 id="快取防護-cache-busting" tabindex="-1">快取防護（Cache Busting）： <a class="header-anchor" href="#快取防護-cache-busting" aria-label="Permalink to &quot;快取防護（Cache Busting）：&quot;">​</a></h3><ul><li><h4 id="public-目錄-1" tabindex="-1">public 目錄 <a class="header-anchor" href="#public-目錄-1" aria-label="Permalink to &quot;public 目錄&quot;">​</a></h4><p>檔案在建構（Build）時會原封不動地被複製到產出目錄（<code>.output/public/</code>）下。若更新了圖片但檔名不變（依然是 <code>/bg.png</code>），可能因為瀏覽器的快取機制，導致使用者依然看到舊圖。</p></li><li><h4 id="assets-目錄-1" tabindex="-1">assets 目錄 <a class="header-anchor" href="#assets-目錄-1" aria-label="Permalink to &quot;assets 目錄&quot;">​</a></h4><p>檔案在建構時通常會被加上一組 <code>雜湊值（Hash）</code>，例如將 <code>bg.png</code> 處理後變成 <code>bg.0a299ea1.png</code>，並放置在 .<code>output/public/_nuxt/</code> 下。每當檔案內容更新，<code>Hash</code> 都會隨之改變，能有效防止瀏覽器快取導致網站更新失效的問題。</p></li></ul></li><li><h3 id="使用情境判斷" tabindex="-1">使用情境判斷： <a class="header-anchor" href="#使用情境判斷" aria-label="Permalink to &quot;使用情境判斷：&quot;">​</a></h3><ul><li><h4 id="建議放置於-assets" tabindex="-1">建議放置於 assets <a class="header-anchor" href="#建議放置於-assets" aria-label="Permalink to &quot;建議放置於 assets&quot;">​</a></h4><p>多數情況下的靜態資源、圖片、CSS、SFC（單一元件檔）內部引用的檔案。</p></li><li><h4 id="必須放置於-public" tabindex="-1">必須放置於 public <a class="header-anchor" href="#必須放置於-public" aria-label="Permalink to &quot;必須放置於 public&quot;">​</a></h4><p>當有例外情況不適合被加工、需要維持絕對路徑且檔名不可被更改時（例如 robots.txt、sitemap.xml 或 favicon.ico），就必須放在 <code>public</code> 目錄提供存取。</p></li></ul></li></ul><p><img src="`+t+'" alt="nuxt3_26_01"></p><h2 id="小結" tabindex="-1">小結 <a class="header-anchor" href="#小結" aria-label="Permalink to &quot;小結&quot;">​</a></h2><ul><li><p>了解 <code>public</code> 與 <code>assets</code> 目錄的運作原理與打包後的結構差異，有助於開發者正確安排靜態資源的存放位置。</p></li><li><p>善用 <code>assets</code> 目錄可以藉由編譯工具加上 <code>Hash</code> 機制，解決前端常見的瀏覽器快取問題； 而 <code>public</code> 則是提供固定路由與特定檔案（如搜尋引擎所需的設定檔）的最佳位置。</p></li></ul>',11)])])}const k=e(c,[["render",n]]);export{b as __pageData,k as default};
